package com.allthinkstars.framework.iot.ai.logging;

import org.slf4j.MDC;

import java.util.LinkedHashMap;
import java.util.Map;

/**
 * AI tool 调用日志上下文
 * 通过 MDC 给当前线程上的日志事件打标，避免共享组件感知 AI 场景
 */
public final class AiLogContext implements AutoCloseable {

    public static final String AI_CHAIN = "aiChain";
    public static final String AI_CONVERSATION_ID = "aiConversationId";
    public static final String AI_TOOL_CALL_ID = "aiToolCallId";
    public static final String AI_TOOL_NAME = "aiToolName";
    public static final String AI_TENANT_ID = "aiTenantId";
    public static final String AI_USER_ID = "aiUserId";

    private final Map<String, String> previousValues = new LinkedHashMap<>();
    private final Map<String, Boolean> existed = new LinkedHashMap<>();

    private AiLogContext(Map<String, String> values) {
        values.forEach((key, value) -> {
            existed.put(key, MDC.get(key) != null);
            previousValues.put(key, MDC.get(key));
            if (value == null || value.isBlank()) {
                MDC.remove(key);
            } else {
                MDC.put(key, value);
            }
        });
    }

    public static AiLogContext openRoot(String tenantId, Long userId) {
        Map<String, String> values = new LinkedHashMap<>();
        values.put(AI_CHAIN, "true");
        values.put(AI_TENANT_ID, safeText(tenantId));
        values.put(AI_USER_ID, userId == null ? null : String.valueOf(userId));
        return new AiLogContext(values);
    }

    public static AiLogContext openToolCall(String conversationId,
                                            String toolCallId,
                                            String toolName,
                                            String tenantId,
                                            Long userId) {
        Map<String, String> values = new LinkedHashMap<>();
        values.put(AI_CHAIN, "true");
        values.put(AI_CONVERSATION_ID, safeText(conversationId));
        values.put(AI_TOOL_CALL_ID, safeText(toolCallId));
        values.put(AI_TOOL_NAME, safeText(toolName));
        values.put(AI_TENANT_ID, safeText(tenantId));
        values.put(AI_USER_ID, userId == null ? null : String.valueOf(userId));
        return new AiLogContext(values);
    }

    private static String safeText(String value) {
        if (value == null || value.isBlank()) {
            return null;
        }
        return value;
    }

    @Override
    public void close() {
        previousValues.forEach((key, previousValue) -> {
            if (Boolean.TRUE.equals(existed.get(key))) {
                MDC.put(key, previousValue);
                return;
            }
            MDC.remove(key);
        });
    }
}

